    "primary_intent": "获取重疾险轻症赔付规则的具体信息（能否多次赔、每次赔多少）",
    "key_entities": ["轻症", "赔付次数", "赔付金额", "基本保额"],
    "expected_response_type": "解释性、有明确范围和示例的回答，并附风险提示",
    "urgency": "medium"
  },
